import React, { useEffect, useState } from 'react';
import axios from 'axios';
import NoteForm from './components/NoteForm';
import NoteList from './components/NoteList';

function App() {
  const [notes, setNotes] = useState([]);

  const fetchNotes = async () => {
    try {
      const res = await axios.get('http://localhost:5001/api/notes');
      setNotes(res.data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => { fetchNotes(); }, []);

  const containerStyle = {
    minHeight: '100vh',
    backgroundColor: '#f1f5f9',
    fontFamily: "'Inter', system-ui, sans-serif",
    padding: '40px 20px',
    color: '#1e293b'
  };

  const headerStyle = {
    textAlign: 'center',
    marginBottom: '40px'
  };

  return (
    <div style={containerStyle}>
      <header style={headerStyle}>
        <h1 style={{ fontSize: '2.5rem', fontWeight: '800', color: '#4f46e5', margin: 0 }}>Vault.io</h1>
        <p style={{ color: '#64748b', marginTop: '8px' }}>Secure documentation for your DevOps workflow</p>
      </header>

      <div style={{ maxWidth: '1100px', margin: '0 auto' }}>
        <NoteForm fetchNotes={fetchNotes} />
        <NoteList notes={notes} fetchNotes={fetchNotes} />
      </div>
    </div>
  );
}

export default App;
